import { Link } from "react-router-dom"

export default function RestaurantCard({ data }) {
  return (
    <div>
      <h3>{data.name}</h3>
      <p>{data.cuisine_type}</p>
      <p>{data.avg_rating}</p>
      <Link to={`/restaurant/${data.restaurant_id}`}>View</Link>
    </div>
  )
}
